INSERT INTO `product_translations` (`id`, `product_id`, `locale`, `name`, `description`, `slug`) VALUES
(240, 1, 'fr', 'Kit point de croix — Alpes Suisses', 'Brodez les magnifiques paysages des Alpes suisses en point de croix. Comprend toile Aida 18ct, fils DMC, aiguille et grille couleur A4.', NULL),
(241, 1, 'de', 'Kreuzstich-Set — Schweizer Alpen', 'Sticken Sie die wunderschöne Schweizer Alpenlandschaft in Kreuzstich. Enthält Aida-Stoff 18ct, DMC-Garne, Nadel und A4-Farbmuster.', 'kreuzstich-set-schweizer-alpen'),
(242, 1, 'en', 'Cross Stitch Kit — Swiss Alps', 'Embroider the beautiful Swiss Alpine landscape in cross stitch. Includes 18ct Aida fabric, DMC threads, needle and A4 colour chart.', 'cross-stitch-kit-swiss-alps'),
(243, 2, 'fr', 'Kit point de croix — Fleurs des champs', 'Un bouquet de fleurs champêtres à broder en point de croix. Idéal pour les débutantes. Toile Aida 14ct incluse.', NULL),
(244, 2, 'de', 'Kreuzstich-Set — Wiesenblumen', 'Einen Strauss Wiesenblumen in Kreuzstich sticken. Ideal für Anfänger. Aida-Stoff 14ct inklusive.', 'kreuzstich-set-wiesenblumen'),
(245, 2, 'en', 'Cross Stitch Kit — Wildflowers', 'A wildflower bouquet to embroider in cross stitch. Perfect for beginners. 14ct Aida fabric included.', 'cross-stitch-kit-wildflowers'),
(246, 3, 'fr', 'Kit broderie libre — Lavande de Provence', 'Kit broderie libre avec motif lavande stylisé. Inclut toile de lin naturel, fils dégradés violet, aiguille et instructions détaillées.', NULL),
(247, 3, 'de', 'Freihandstick-Set — Lavendel', 'Freihandstick-Set mit stilisiertem Lavendelmotiv. Enthält Naturleinen, violette Verlaufsgarne, Nadel und detaillierte Anleitung.', 'freihandstick-set-lavendel'),
(248, 3, 'en', 'Free Embroidery Kit — Lavender', 'Free embroidery kit with a stylized lavender motif. Includes natural linen, gradient purple threads, needle and detailed instructions.', 'free-embroidery-kit-lavender'),
(249, 4, 'fr', 'Kit broderie — Animaux de la forêt', 'Brodez un renard, un hérisson et un écureuil dans un décor forestier. Kit complet pour niveau intermédiaire.', NULL),
(250, 4, 'de', 'Stickset — Waldtiere', 'Sticken Sie einen Fuchs, einen Igel und ein Eichhörnchen in einem Waldambiente. Komplettes Set für Fortgeschrittene.', 'stickset-waldtiere'),
(251, 4, 'en', 'Embroidery Kit — Forest Animals', 'Embroider a fox, a hedgehog and a squirrel in a forest setting. Complete kit for intermediate level.', 'embroidery-kit-forest-animals'),
(252, 5, 'fr', 'Coffret fils DMC — 36 couleurs assorties', 'Coffret de 36 échevettes de fils DMC Mouliné Spécial, soigneusement sélectionnées pour la broderie et le point de croix.', NULL),
(253, 5, 'de', 'DMC-Garnkoffer — 36 Farben', 'Koffer mit 36 Strängen DMC Mouliné Spécial, sorgfältig für Stickerei und Kreuzstich ausgewählt.', 'dmc-garnkoffer-36-farben'),
(254, 5, 'en', 'DMC Thread Box — 36 Assorted Colours', 'Box of 36 skeins of DMC Mouliné Spécial, carefully selected for embroidery and cross stitch.', 'dmc-thread-box-36-colours'),
(255, 6, 'fr', 'Fil DMC Mouliné — Blanc B5200', 'Échevette de fil DMC Mouliné Spécial, coloris blanc pur B5200. 8 mètres.', NULL),
(256, 6, 'de', 'DMC Mouliné-Garn — Weiss B5200', 'DMC Mouliné Spécial Strang, Farbe reines Weiss B5200. 8 Meter.', 'dmc-mouline-garn-weiss'),
(257, 6, 'en', 'DMC Mouliné Thread — White B5200', 'DMC Mouliné Spécial skein, pure white colour B5200. 8 metres.', 'dmc-mouline-thread-white'),
(258, 7, 'fr', 'Fil DMC Mouliné — Rouge 321', 'Échevette de fil DMC Mouliné Spécial, coloris rouge vif 321. 8 mètres.', NULL),
(259, 7, 'de', 'DMC Mouliné-Garn — Rot 321', 'DMC Mouliné Spécial Strang, Farbe leuchtendrot 321. 8 Meter.', 'dmc-mouline-garn-rot'),
(260, 7, 'en', 'DMC Mouliné Thread — Red 321', 'DMC Mouliné Spécial skein, bright red colour 321. 8 metres.', 'dmc-mouline-thread-red'),
(261, 8, 'fr', 'Coffret fils Anchor — 20 couleurs', 'Coffret de 20 échevettes Anchor Mouliné, idéal pour débuter ou compléter sa collection.', NULL),
(262, 8, 'de', 'Anchor-Garnset — 20 Farben', 'Set mit 20 Anchor Mouliné Strängen, ideal zum Starten oder Ergänzen der Sammlung.', 'anchor-garnset-20-farben'),
(263, 8, 'en', 'Anchor Thread Set — 20 Colours', 'Set of 20 Anchor Mouliné skeins, ideal to start or complete your collection.', 'anchor-thread-set-20-colours'),
(264, 9, 'fr', 'Toile Aida blanche 18ct — 50x50cm', 'Toile Aida de qualité supérieure, 18 points au cm, blanc pur. Idéale pour le point de croix fin.', NULL),
(265, 9, 'de', 'Weisser Aida-Stoff 18ct — 50x50cm', 'Aida-Stoff in Premiumqualität, 18 Punkte pro cm, reinweiss. Ideal für feinen Kreuzstich.', 'aida-stoff-weiss-18ct'),
(266, 9, 'en', 'White Aida Fabric 18ct — 50x50cm', 'Premium quality Aida fabric, 18 count, pure white. Ideal for fine cross stitch.', 'aida-fabric-white-18ct'),
(267, 10, 'fr', 'Toile Aida écrue 14ct — 50x50cm', 'Toile Aida teinte écrue naturelle, 14 points au cm. Format idéal pour les projets moyens.', NULL),
(268, 10, 'de', 'Ecru Aida-Stoff 14ct — 50x50cm', 'Aida-Stoff in natürlicher Ecrufarbe, 14 Punkte pro cm. Ideales Format für mittlere Projekte.', 'aida-stoff-ecru-14ct'),
(269, 10, 'en', 'Ecru Aida Fabric 14ct — 50x50cm', 'Natural ecru Aida fabric, 14 count. Ideal size for medium-sized projects.', 'aida-fabric-ecru-14ct'),
(270, 11, 'fr', 'Toile de lin naturel 28ct — 50x70cm', 'Lin naturel haut de gamme, 28 points au cm. Pour broderie libre et point de croix raffiné.', NULL),
(271, 11, 'de', 'Naturleinen 28ct — 50x70cm', 'Premium-Naturleinen, 28 Punkte pro cm. Für Freihandstickerei und raffinierten Kreuzstich.', 'naturleinen-28ct'),
(272, 11, 'en', 'Natural Linen 28ct — 50x70cm', 'Premium natural linen, 28 count. For free embroidery and refined cross stitch.', 'natural-linen-28ct'),
(273, 12, 'fr', 'Cerceau à broder en bois — 15cm', 'Cerceau à broder en bois de hêtre, diamètre 15cm. Finition lisse, idéal pour débutants.', NULL),
(274, 12, 'de', 'Holz-Stickrahmen — 15cm', 'Stickrahmen aus Buchenholz, Durchmesser 15cm. Glatte Oberfläche, ideal für Anfänger.', 'holz-stickrahmen-15cm'),
(275, 12, 'en', 'Wooden Embroidery Hoop — 15cm', 'Beech wood embroidery hoop, 15cm diameter. Smooth finish, ideal for beginners.', 'wooden-hoop-15cm'),
(276, 13, 'fr', 'Cerceau à broder en bois — 25cm', 'Cerceau à broder en bois de hêtre, diamètre 25cm. Pour les projets de taille moyenne.', NULL),
(277, 13, 'de', 'Holz-Stickrahmen — 25cm', 'Stickrahmen aus Buchenholz, Durchmesser 25cm. Für mittelgrosse Projekte.', 'holz-stickrahmen-25cm'),
(278, 13, 'en', 'Wooden Embroidery Hoop — 25cm', 'Beech wood embroidery hoop, 25cm diameter. For medium-sized projects.', 'wooden-hoop-25cm'),
(279, 14, 'fr', 'Cadre bois rectangulaire — 20x30cm', 'Cadre à broder rectangulaire en bois massif, 20x30cm. Idéal pour tableaux et projets déco.', NULL),
(280, 14, 'de', 'Rechteckiger Holzrahmen — 20x30cm', 'Rechteckiger Stickrahmen aus Massivholz, 20x30cm. Ideal für Wandbilder und Deko-Projekte.', 'rechteckiger-holzrahmen'),
(281, 14, 'en', 'Rectangular Wood Frame — 20x30cm', 'Rectangular embroidery frame in solid wood, 20x30cm. Ideal for wall art and deco projects.', 'rectangular-wood-frame'),
(282, 15, 'fr', 'Aiguilles de tapisserie — paquet de 10', 'Aiguilles de tapisserie à bout rond, taille 24/26. Paquet de 10 aiguilles en acier inoxydable.', NULL),
(283, 15, 'de', 'Tapisserie-Nadeln — 10er Pack', '10 Tapisserie-Nadeln mit stumpfer Spitze, Grösse 24/26. Aus rostfreiem Stahl.', 'tapisserie-nadeln-10er'),
(284, 15, 'en', 'Tapestry Needles — Pack of 10', 'Blunt-tipped tapestry needles, size 24/26. Pack of 10 stainless steel needles.', 'tapestry-needles-10'),
(288, 16, 'fr', 'Kit point de croix — Chalet alpin', 'Brodez un authentique chalet alpin suisse. Toile Aida 16ct, fils DMC sélectionnés, guide de points illustré.', NULL),
(289, 17, 'fr', 'Kit point de croix — Lac Léman', 'Panorama du lac Léman avec les Alpes en toile de fond. Idéal niveau intermédiaire.', NULL),
(290, 18, 'fr', 'Kit point de croix — Ours brun', 'Adorable ourson en forêt, rendu réaliste grâce aux dégradés DMC. Niveau débutant avancé.', NULL),
(291, 19, 'fr', 'Kit point de croix — Mandala zen', 'Mandala géométrique aux couleurs apaisantes. Méditation et concentration garanties.', NULL),
(292, 20, 'fr', 'Kit point de croix — Papillons', 'Quatre espèces de papillons suisses à broder sur toile écrue. Idéal cadeau.', NULL),
(293, 21, 'fr', 'Kit point de croix — Noël Sapins', 'Décoration de Noël traditionnelle à broder. Sapins enneigés et étoiles dorées.', NULL),
(294, 22, 'fr', 'Kit point de croix — Moutons de l\'Engadine', 'Moutons de race Engadinoise dans un paysage montagnard. Édition limitée.', NULL),
