(467, 125, 'de', 'Schererset Stickerei — 3 Stk + Ledertui', 'Set 3 Stickscheren im Ledertui: Schneidschere 21cm, Spitzschere 15cm, Hühnchenschere 11cm.', NULL),
(468, 131, 'de', 'Anfänger-Set — Kreuzstich', 'Komplettes Einführungsset Kreuzstich: Aida-Stoff, DMC-Garne, Nadeln und illustriertes Muster.', NULL),
(469, 135, 'de', 'Einführungsset — Makramee', 'Makramee-Starterkit: 3mm Schnur 50m, Holzring, Perlen und Wandhänger-Tutorial.', NULL),
(470, 136, 'de', 'Prestige-Coffret — Seide & Gold', 'Luxusset für erfahrene Stickerinnen: Madeira Seidengarne, Goldgarne, Premium-Leinen, Exklusivmuster.', NULL),
(471, 146, 'de', 'Saisonales Set — Herbstpilze', 'Steinpilze und Pfifferlinge in freier Stickerei. Terracotta-Palette, Waldatmosphäre.', NULL),
(472, 147, 'de', 'Saisonales Set — Winterrentier', 'Nordisches Rentier auf Schneegrund im Kreuzstich. Weihnachts-Set, mittleres Niveau.', NULL),
(473, 148, 'de', 'Saisonales Set — Weihnachtssterne', 'Skandinavischer Sternenvorhang in Rot und Weiss gestickt. Zeitlose Weihnachtsdekoration.', NULL),
(474, 155, 'de', 'Einlagen-Sortiment — 3 Typen', 'Set mit 3 Einlagen (Bügeleinlage, aufreissbar, löslich) je 30x50cm. Vollständige Entdeckung.', NULL),
(475, 158, 'de', 'Maschinenstickgarn Metallic Gold — 200m', 'Goldenes Metallic-Garn 40wt, Spule 200m. Strahlende Goldakzente auf Maschinenstickereien.', NULL),
